-- =========================================================================
-- 4B Vocabulary Load for Rosie Learning Platform
-- 223 words across Units 7–12, generated 2026-06-05
--
-- HOW TO USE
--   1. Open Supabase Dashboard → SQL Editor → New query
--   2. Replace `YOUR_LOGIN_EMAIL_HERE` (line below) with your Supabase auth email
--   3. Click RUN. Should complete in a few seconds.
--   4. Verify: SELECT COUNT(*) FROM word_entries WHERE stage = '4B';
--      Expected: 223
--   5. (Optional) After success, delete this file — it is a one-time script.
--
-- BEHAVIOR
--   Wraps DELETE-of-4B and INSERT-223 in a single transaction. Safe to re-run.
--   Touches ONLY stage='4B' rows. All other stages (4A etc.) are untouched.
--   Uses DELETE+INSERT instead of UPSERT because the table currently has no
--   (unit,lesson,word,stage) unique constraint required by ON CONFLICT.
-- =========================================================================

BEGIN;

-- Clear any prior 4B rows (no-op on first run)
DELETE FROM word_entries WHERE stage = '4B';

-- Insert all 223 4B rows in one statement
WITH me AS (
  SELECT id FROM auth.users WHERE email = 'rosie@rosie.app' LIMIT 1
)
INSERT INTO word_entries
  (creator, stage, unit, lesson, word, explanation, ipa, example, chinese_def)
SELECT
  me.id, d.stage, d.unit, d.lesson, d.word, d.explanation, d.ipa, d.example, d.chinese_def
FROM me, (VALUES
  ($$4B$$, $$Unit 7$$, $$Lesson 1$$, $$national park$$, $$an area of land that is protected by the government for people to visit because of its natural beauty and historical or scientific interest$$, $$/ˈnæʃnəl pɑːk/$$, $$Last summer we visited a national park and saw three iguanas.$$, $$国家公园$$),
  ($$4B$$, $$Unit 7$$, $$Lesson 1$$, $$iguana$$, $$a large tropical American lizard$$, $$/ɪˈɡwɑːnə/$$, $$Dad showed me a green iguana sitting on a warm rock.$$, $$鬣蜥$$),
  ($$4B$$, $$Unit 7$$, $$Lesson 1$$, $$branch$$, $$a part of a tree that grows out from the trunk$$, $$/brɑːntʃ/$$, $$A little bird was singing on a branch of the apple tree.$$, $$树枝$$),
  ($$4B$$, $$Unit 7$$, $$Lesson 1$$, $$jungle$$, $$an area of tropical forest where trees and plants grow very thickly$$, $$/ˈdʒʌŋɡl/$$, $$We saw colourful parrots flying high above the green jungle.$$, $$丛林；热带雨林$$),
  ($$4B$$, $$Unit 7$$, $$Lesson 1$$, $$lay eggs$$, $$to produce and put eggs outside the body, like birds do$$, $$/leɪ eɡz/$$, $$Our hens lay eggs every morning in the little wooden box.$$, $$产卵；下蛋$$),
  ($$4B$$, $$Unit 7$$, $$Lesson 1$$, $$sand$$, $$the very tiny, loose pieces of rock that cover beaches, deserts, etc.$$, $$/sænd/$$, $$Rosie built a tall sand castle on the sunny beach.$$, $$沙子$$),
  ($$4B$$, $$Unit 7$$, $$Lesson 1$$, $$leaf$$, $$a flat green part of a plant, growing from a stem or branch or from the root$$, $$/liːf/$$, $$A tiny caterpillar was eating a green leaf in the garden.$$, $$叶子$$),
  ($$4B$$, $$Unit 7$$, $$Lesson 1$$, $$volcano$$, $$a mountain with a hole in the top or side that sometimes sends out rocks, ash, lava, etc., in a sudden explosion (called an eruption)$$, $$/vɒlˈkeɪnəʊ/$$, $$The huge volcano on the island sent smoke high into the sky.$$, $$火山$$),
  ($$4B$$, $$Unit 7$$, $$Lesson 1$$, $$nest$$, $$the place where a bird lays its eggs and takes care of its young$$, $$/nest/$$, $$Three baby birds were chirping happily in their cosy nest.$$, $$鸟巢；窝$$),
  ($$4B$$, $$Unit 7$$, $$Lesson 1$$, $$wildlife$$, $$animals living in nature$$, $$/ˈwaɪldlaɪf/$$, $$The national park is home to lots of amazing wildlife.$$, $$野生动物$$),
  ($$4B$$, $$Unit 7$$, $$Lesson 1$$, $$soil$$, $$the top layer of earth in which plants grow$$, $$/sɔɪl/$$, $$We dug holes in the soft soil to plant our sunflower seeds.$$, $$土壤$$),
  ($$4B$$, $$Unit 7$$, $$Lesson 1$$, $$erupt$$, $$to send out rocks, ash, lava, etc., in a sudden explosion$$, $$/ɪˈrʌpt/$$, $$The old volcano can still erupt and send out red lava.$$, $$（火山）喷发$$),
  ($$4B$$, $$Unit 7$$, $$Lesson 1$$, $$stone$$, $$a small piece of rock of any shape$$, $$/stəʊn/$$, $$Rosie picked up a smooth grey stone beside the river.$$, $$石头$$),
  ($$4B$$, $$Unit 7$$, $$Lesson 1$$, $$active$$, $$likely to explode violently or produce fire and hot liquid rock$$, $$/ˈæktɪv/$$, $$The active volcano on the island sometimes shoots out hot lava.$$, $$（火山）活跃的；活火山的$$),
  ($$4B$$, $$Unit 7$$, $$Lesson 2$$, $$humid$$, $$(of the air or climate) warm and slightly wet$$, $$/ˈhjuːmɪd/$$, $$The jungle air felt very humid and sticky in the afternoon.$$, $$潮湿的；湿润的$$),
  ($$4B$$, $$Unit 7$$, $$Lesson 2$$, $$smell$$, $$the quality of a thing that you can sense with your nose$$, $$/smel/$$, $$I love the sweet smell of Mum's freshly baked cookies.$$, $$气味$$),
  ($$4B$$, $$Unit 7$$, $$Lesson 2$$, $$alive$$, $$living; not dead$$, $$/əˈlaɪv/$$, $$The little fish we found in the pond was still alive.$$, $$活着的；有生命的$$),
  ($$4B$$, $$Unit 7$$, $$Lesson 2$$, $$creature$$, $$a living thing, real or imaginary, that can move around, such as an animal$$, $$/ˈkriːtʃə/$$, $$A tiny furry creature was hiding under the garden bench.$$, $$生物；动物$$),
  ($$4B$$, $$Unit 7$$, $$Lesson 2$$, $$curious$$, $$having a strong desire to know about something$$, $$/ˈkjʊəriəs/$$, $$Rosie is very curious about how baby chicks hatch from eggs.$$, $$好奇的$$),
