  ($$4B$$, $$Unit 9$$, $$Lesson 2$$, $$square$$, $$an open area in a town, usually with four sides, surrounded by buildings$$, $$/skweə/$$, $$Children played with balloons in the town square on Sunday.$$, $$广场$$),
  ($$4B$$, $$Unit 9$$, $$Lesson 2$$, $$steps$$, $$the surfaces that you walk on when you go up or down stairs$$, $$/steps/$$, $$We sat on the steps in front of our house.$$, $$台阶；楼梯$$),
  ($$4B$$, $$Unit 9$$, $$Lesson 2$$, $$outer space$$, $$the area outside the earth's atmosphere where all the other planets and stars are$$, $$/ˈaʊtə speɪs/$$, $$Astronauts travel to outer space inside very fast rockets.$$, $$外太空；太空$$),
  ($$4B$$, $$Unit 9$$, $$Lesson 2$$, $$bagel$$, $$a hard bread roll in the shape of a ring$$, $$/ˈbeɪɡl/$$, $$I ate a warm bagel with cream cheese for breakfast.$$, $$百吉饼；贝果$$),
  ($$4B$$, $$Unit 9$$, $$Lesson 2$$, $$chewy$$, $$needing to be chewed a lot before it can be eaten$$, $$/ˈtʃuːi/$$, $$The toffee sweets in my lunchbox are very chewy.$$, $$有嚼劲的；耐嚼的$$),
  ($$4B$$, $$Unit 9$$, $$Lesson 3$$, $$opinion$$, $$your feelings or thoughts about somebody/something, rather than a fact$$, $$/əˈpɪnjən/$$, $$My opinion is that puppies make the very best pets.$$, $$观点；看法$$),
  ($$4B$$, $$Unit 9$$, $$Lesson 3$$, $$origin$$, $$the beginning or cause of something$$, $$/ˈɒrɪdʒɪn/$$, $$Our teacher told us about the origin of the pizza.$$, $$起源；由来$$),
  ($$4B$$, $$Unit 9$$, $$Lesson 3$$, $$material$$, $$a substance that things can be made from$$, $$/məˈtɪəriəl/$$, $$We used soft material to make a cosy dog bed.$$, $$材料；原料$$),
  ($$4B$$, $$Unit 9$$, $$Lesson 3$$, $$local$$, $$belonging to or connected with the particular place or area that you are talking about or with the place where you live$$, $$/ˈləʊkl/$$, $$We buy fresh apples from the local farm every weekend.$$, $$当地的；本地的$$),
  ($$4B$$, $$Unit 9$$, $$Lesson 3$$, $$jog$$, $$to run slowly especially for exercise$$, $$/dʒɒɡ/$$, $$Dad and I jog around the park every Saturday morning.$$, $$慢跑（锻炼）$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 1$$, $$social media$$, $$websites and software programs used for social networking$$, $$/ˈsəʊʃl ˈmiːdiə/$$, $$Mum says I'm too young to use social media yet.$$, $$社交媒体$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 1$$, $$album$$, $$a book in which you keep photographs, stamps, etc.$$, $$/ˈælbəm/$$, $$Grandma showed me an old album full of family photos.$$, $$相册；集邮册$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 1$$, $$app$$, $$a piece of software that you can download to a device such as a smartphone or tablet, for example to look up information or to play a game$$, $$/æp/$$, $$Dad downloaded a new maths app for my tablet.$$, $$应用程序$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 1$$, $$print$$, $$to cause (words, images, etc.) to appear on paper or cloth by using a machine (called a printer)$$, $$/prɪnt/$$, $$My teacher asked me to print the homework on white paper.$$, $$打印；印刷$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 1$$, $$digital$$, $$of or relating to information that is stored in the form of the numbers 0 and 1$$, $$/ˈdɪdʒɪtl/$$, $$I keep all my holiday photos in a digital album.$$, $$数字的；数码的$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 1$$, $$show$$, $$to let somebody see something$$, $$/ʃəʊ/$$, $$Please show me your new puppy after school today.$$, $$给…看；展示$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 1$$, $$download$$, $$to get data from another computer, usually using the internet$$, $$/ˌdaʊnˈləʊd/$$, $$Can I download this game onto your phone, Dad?$$, $$下载$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 1$$, $$comment$$, $$something that you say or write that gives an opinion on or explains somebody/something$$, $$/ˈkɒment/$$, $$My friend left a kind comment under my drawing online.$$, $$评论；意见$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 1$$, $$internet$$, $$a system that connects computers throughout the world$$, $$/ˈɪntənet/$$, $$We use the internet to find fun science facts at home.$$, $$互联网$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 1$$, $$post$$, $$to put information or pictures on a website$$, $$/pəʊst/$$, $$Mum likes to post photos of our dog online.$$, $$发布（信息或图片到网上）$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 1$$, $$upload$$, $$to send data to another computer$$, $$/ˌʌpˈləʊd/$$, $$I'll upload my school project to the class website tonight.$$, $$上传$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 1$$, $$share$$, $$to give some of what you have to somebody else$$, $$/ʃeə(r)/$$, $$I always share my cookies with my little sister.$$, $$分享$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 1$$, $$film$$, $$special thin plastic used for making photographs or moving pictures, used in cameras$$, $$/fɪlm/$$, $$Grandpa's old camera still needs a roll of film.$$, $$胶卷；胶片$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 1$$, $$rugby$$, $$A game played by two teams of 13 or 15 players, using an oval ball which may be kicked or carried. Teams try to put the ball over the other team's line.$$, $$/ˈrʌɡbi/$$, $$My brother plays rugby with his friends every Saturday morning.$$, $$橄榄球（运动）$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 1$$, $$selfie$$, $$a photo of yourself that you take, typically with a smartphone or webcam, and usually put on social media$$, $$/ˈselfi/$$, $$We took a funny selfie with the puppy at the park.$$, $$自拍照$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 1$$, $$sticker$$, $$a small digital image that you can use to express an idea or emotion on social media or on a messaging app$$, $$/ˈstɪkə(r)/$$, $$I sent Mum a smiling cat sticker after lunch.$$, $$（聊天/社交媒体上的）表情贴纸$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 2$$, $$invent$$, $$to create or produce (something useful) for the first time$$, $$/ɪnˈvent/$$, $$One day I want to invent a robot that cleans rooms.$$, $$发明；创造$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 2$$, $$programme (AmE program)$$, $$something that people watch on television or listen to on the radio$$, $$/ˈprəʊɡræm/$$, $$My favourite programme about animals starts at seven tonight.$$, $$（电视或广播）节目$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 2$$, $$quality$$, $$how good or bad something is$$, $$/ˈkwɒləti/$$, $$The quality of this new cartoon is really wonderful.$$, $$质量；品质$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 2$$, $$record$$, $$to store (something, such as sounds, music, images, etc.) on tape or on a disk so that it can be heard or seen later$$, $$/rɪˈkɔːd/$$, $$Dad will record the football match for me to watch later.$$, $$录制；录音$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 2$$, $$technology$$, $$the use of science in industry, engineering, etc., to invent useful things or to solve problems$$, $$/tekˈnɒlədʒi/$$, $$New technology helps farmers grow tastier fruit and vegetables.$$, $$技术；科技$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 2$$, $$entertain$$, $$to interest somebody or make somebody laugh in order to please them$$, $$/ˌentəˈteɪn/$$, $$Dad tells funny stories to entertain us during long car trips.$$, $$使快乐；使有兴趣$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 2$$, $$imagine$$, $$to form a picture in your mind of what something might be like$$, $$/ɪˈmædʒɪn/$$, $$I like to imagine flying over the mountains with my dog.$$, $$想象$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 2$$, $$cartoon$$, $$an animated film or television show$$, $$/kɑːˈtuːn/$$, $$My little brother watches a cartoon about rabbits every morning.$$, $$动画片；卡通片$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 2$$, $$documentary$$, $$a film or a radio or television programme giving facts about something$$, $$/ˌdɒkjuˈmentri/$$, $$We watched a documentary about pandas in the bamboo forest.$$, $$纪录片$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 2$$, $$news$$, $$information that is reported in a newspaper, magazine, television news programme, etc.$$, $$/njuːz/$$, $$Grandpa watches the evening news while eating his dinner.$$, $$新闻$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 2$$, $$reality show$$, $$television shows that are based on real people (not actors) in real situations, presented as entertainment$$, $$/riˈæləti ʃəʊ/$$, $$Mum loves a cooking reality show with real families competing.$$, $$真人秀$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 2$$, $$series$$, $$a set of regularly presented television shows involving the same group of characters or the same subject$$, $$/ˈsɪəriːz/$$, $$My favourite series about magic ponies has a new episode tonight.$$, $$（电视）系列节目；剧集$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 2$$, $$sitcom$$, $$a regular comedy programme on television that shows the same characters in different funny situations$$, $$/ˈsɪtkɒm/$$, $$We laugh together at our favourite family sitcom every Friday night.$$, $$情景喜剧$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 2$$, $$virtual reality$$, $$images and sounds created by a computer that seem almost real to the user, who can interact with them by using sensors (= VR)$$, $$/ˌvɜːtʃuəl riˈæləti/$$, $$My cousin tried virtual reality and swam with friendly cartoon dolphins.$$, $$虚拟现实（VR）$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 3$$, $$follower$$, $$a person who chooses to regularly receive somebody's messages using a social media service$$, $$/ˈfɒləʊə(r)/$$, $$My aunt has a new follower on her cooking page today.$$, $$（社交媒体上的）关注者；粉丝$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 3$$, $$channel$$, $$a television station$$, $$/ˈtʃænl/$$, $$There is a channel that shows cartoons all day long.$$, $$（电视）频道；电视台$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 3$$, $$review$$, $$a report in the media in which someone gives their opinion of something such as a new book or movie$$, $$/rɪˈvjuː/$$, $$I read a great review of that new dinosaur film online.$$, $$评论文章；评价$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 3$$, $$review (verb)$$, $$to write a report of a book, play, film, product, etc. in which you give your opinion of it$$, $$/rɪˈvjuː/$$, $$My sister loves to review her favourite story books online.$$, $$评论；写评论$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 3$$, $$voice$$, $$the sounds that are made when people speak or sing$$, $$/vɔɪs/$$, $$My grandma has a soft, kind voice when she sings.$$, $$嗓音；声音$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 3$$, $$generous$$, $$freely giving or sharing money and other valuable things$$, $$/ˈdʒenərəs/$$, $$My generous uncle always brings sweets for all the children.$$, $$慷慨的；大方的$$),
  ($$4B$$, $$Unit 10$$, $$Lesson 3$$, $$neighbourhood (AmE neighborhood)$$, $$a district or an area of a town$$, $$/ˈneɪbəhʊd/$$, $$Lots of friendly cats live in our quiet neighbourhood.$$, $$街区；社区$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 1$$, $$destination$$, $$a place to which a person is going or something is being sent$$, $$/ˌdestɪˈneɪʃn/$$, $$Our holiday destination this summer is a sunny beach in Spain.$$, $$目的地$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 1$$, $$bus stop$$, $$a place at the side of a road that is marked with a sign, where buses stop$$, $$/bʌs stɒp/$$, $$Mum waits with me at the bus stop every school morning.$$, $$公共汽车站$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 1$$, $$get on$$, $$to enter a vehicle (bus, train, plane, etc.)$$, $$/ɡet ɒn/$$, $$We get on the school bus right after breakfast each day.$$, $$上车$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 1$$, $$driver$$, $$a person who drives a vehicle$$, $$/ˈdraɪvə(r)/$$, $$Our bus driver smiled and waved at every child this morning.$$, $$司机$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 1$$, $$get off$$, $$to leave a vehicle (bus, train, plane, etc.)$$, $$/ɡet ɒf/$$, $$We get off the train at the next stop near grandma's house.$$, $$下车$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 1$$, $$bike lane$$, $$a part of a road that only bicycles are allowed to use$$, $$/baɪk leɪn/$$, $$Dad and I rode safely along the new bike lane on Sunday.$$, $$自行车道$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 1$$, $$parking$$, $$a space or an area for leaving vehicles$$, $$/ˈpɑːkɪŋ/$$, $$The parking near the playground was full on Saturday afternoon.$$, $$停车场；停车位$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 1$$, $$tram$$, $$a vehicle that travels on streets on metal tracks and that is used for carrying passengers$$, $$/træm/$$, $$We took a bright yellow tram to the museum in the city.$$, $$有轨电车$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 1$$, $$pedestrian$$, $$a person walking in the street and not travelling in a vehicle$$, $$/pəˈdestriən/$$, $$A kind pedestrian helped my little brother cross the busy road.$$, $$行人$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 1$$, $$motorbike$$, $$a road vehicle with two wheels, driven by an engine, with one seat for the driver and often a seat for a passenger behind the driver$$, $$/ˈməʊtəbaɪk/$$, $$My uncle rides his shiny red motorbike to work every day.$$, $$摩托车$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 1$$, $$traffic$$, $$the vehicles that are on a road at a particular time$$, $$/ˈtræfɪk/$$, $$The traffic was very heavy on our way home from school.$$, $$交通；车流$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 1$$, $$scooter$$, $$a light motorbike, usually with small wheels and a curved cover at the front to protect the rider's legs$$, $$/ˈskuːtə(r)/$$, $$My cousin rides a little blue scooter to the corner shop.$$, $$小型摩托车$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 1$$, $$resident$$, $$a person who lives in a particular place or who has their home there$$, $$/ˈrezɪdənt/$$, $$Every resident on our street came to the weekend garden party.$$, $$居民$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 1$$, $$transport (AmE transportation)$$, $$a system for carrying people or goods from one place to another using vehicles, roads, etc.$$, $$/ˈtrænspɔːt/$$, $$Buses and trains are the main transport in our small town.$$, $$交通运输$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 1$$, $$planner$$, $$a person whose job is to plan the growth and development of a town$$, $$/ˈplænə(r)/$$, $$The town planner showed us a map of the new playground.$$, $$城市规划师$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 2$$, $$passenger$$, $$a person who is travelling in a car, bus, train, plane or ship and who is not driving it or working on it$$, $$/ˈpæsɪndʒə(r)/$$, $$Every passenger on the bus smiled at the cute little puppy.$$, $$乘客$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 2$$, $$track$$, $$rails (= metal bars) that a train moves along$$, $$/træk/$$, $$We watched the long train rumble loudly along the shiny track.$$, $$铁轨$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 2$$, $$billion$$, $$1,000,000,000; one thousand million$$, $$/ˈbɪljən/$$, $$More than a billion people around the world love football.$$, $$十亿$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 2$$, $$display$$, $$to put something in a place where people can see it easily$$, $$/dɪˈspleɪ/$$, $$Our teacher will display our paintings on the classroom wall today.$$, $$展示；陈列$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 2$$, $$inspector$$, $$a person whose job is to check tickets on a bus or train$$, $$/ɪnˈspektə(r)/$$, $$The friendly inspector checked our tickets on the train to London.$$, $$检票员$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 2$$, $$escalator$$, $$moving stairs that carry people between different floors of a large building$$, $$/ˈeskəleɪtə(r)/$$, $$We rode the long escalator up to the toy shop floor.$$, $$自动扶梯$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 2$$, $$lift$$, $$a machine that carries people or goods up and down to different levels in a building or a mine$$, $$/lɪft/$$, $$We took the lift up to the tenth floor of the hotel.$$, $$电梯$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 2$$, $$gallery$$, $$a room or building for showing works of art, especially to the public$$, $$/ˈɡæləri/$$, $$Our class visited a bright art gallery on Friday afternoon.$$, $$美术馆；画廊$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 2$$, $$loudspeaker$$, $$a device that is used to make sound (such as music or a person's voice) louder and to send it out so that many people can hear it in a public space$$, $$/ˌlaʊdˈspiːkə(r)/$$, $$The loudspeaker at the station told us our train was late.$$, $$扩音器；喇叭$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 2$$, $$ticket machine$$, $$an automatic device that sells tickets for public transportation (trains, buses, etc.), parking, or events without needing a human cashier$$, $$/ˈtɪkɪt məˌʃiːn/$$, $$Dad bought our train tickets from the shiny ticket machine quickly.$$, $$售票机$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 2$$, $$timetable$$, $$a chart showing the times at which trains, buses and planes leave and arrive$$, $$/ˈtaɪmteɪbl/$$, $$We checked the timetable to find the next train to grandma's.$$, $$时刻表$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 2$$, $$the planet$$, $$the planet Earth$$, $$/ðə ˈplænɪt/$$, $$We must take care of the planet by recycling our rubbish.$$, $$地球$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 2$$, $$chandelier$$, $$a large, decorated light that hangs from a ceiling and has branches for holding many light bulbs or candles$$, $$/ˌʃændəˈlɪə(r)/$$, $$A huge sparkling chandelier hung above the dining table at grandma's.$$, $$枝形吊灯$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 2$$, $$mosaic$$, $$a picture or pattern made by placing together small pieces of glass, stone, etc. of different colours$$, $$/məʊˈzeɪɪk/$$, $$We made a beautiful mosaic of a fish in art class today.$$, $$马赛克；镶嵌画$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 2$$, $$sculpture$$, $$a work of art that is a solid figure or object made by carving or shaping wood, stone, clay, metal, etc.$$, $$/ˈskʌlptʃə(r)/$$, $$A tall stone sculpture of a lion stood near the museum door.$$, $$雕塑$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 3$$, $$pass$$, $$a card or ticket which shows that you are allowed to enter or leave a particular place or to ride a vehicle$$, $$/pɑːs/$$, $$I showed my bus pass to the driver before sitting down.$$, $$通行证；乘车卡$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 3$$, $$gondola$$, $$a long boat with a flat bottom and high parts at each end, used on canals in Venice$$, $$/ˈɡɒndələ/$$, $$We rode a black gondola along a quiet canal in Venice.$$, $$贡多拉（威尼斯小船）$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 3$$, $$romantic$$, $$making someone think of love$$, $$/rəʊˈmæntɪk/$$, $$Mum says a sunset boat ride is very romantic and sweet.$$, $$浪漫的$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 3$$, $$cable car$$, $$a vehicle that hangs from and is pulled by a moving cable and that carries passengers up and down a mountain$$, $$/ˈkeɪbl kɑː(r)/$$, $$We rode a swinging cable car up the snowy mountain yesterday.$$, $$缆车$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 3$$, $$means$$, $$a way of achieving or doing something$$, $$/miːnz/$$, $$Riding bikes is a fun means of getting to school quickly.$$, $$方法；方式$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 3$$, $$aquarium$$, $$a building where people can go to see fish and other water creatures$$, $$/əˈkweəriəm/$$, $$We saw a giant turtle at the aquarium on Saturday morning.$$, $$水族馆$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 3$$, $$entire$$, $$including everything, everyone or every part$$, $$/ɪnˈtaɪə(r)/$$, $$My entire family went to the park for a big picnic.$$, $$整个的；全部的$$),
  ($$4B$$, $$Unit 11$$, $$Lesson 3$$, $$distance$$, $$the amount of space between two places or things$$, $$/ˈdɪstəns/$$, $$The distance from our house to school is about one kilometre.$$, $$距离$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 1$$, $$check$$, $$to look at (something) carefully to find mistakes, problems, etc., or to make sure there is nothing wrong with it$$, $$/tʃek/$$, $$Please check your homework before you put it in your bag.$$, $$检查；查看$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 1$$, $$artist$$, $$a person who creates art$$, $$/ˈɑːtɪst/$$, $$My sister wants to be an artist when she grows up.$$, $$艺术家$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 1$$, $$patient$$, $$able to wait for a long time or accept annoying behaviour or difficulties without becoming angry$$, $$/ˈpeɪʃnt/$$, $$Be patient and wait for your turn on the slide.$$, $$有耐心的$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 1$$, $$chef$$, $$a professional cook who usually is in charge of a kitchen in a restaurant$$, $$/ʃef/$$, $$The chef made us a delicious pizza for dinner.$$, $$厨师；大厨$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 1$$, $$customer$$, $$a person who buys goods or services from a shop or business$$, $$/ˈkʌstəmə(r)/$$, $$The shop owner smiled kindly at every customer who came in.$$, $$顾客$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 1$$, $$detective$$, $$a person, especially a police officer, whose job is to investigate crimes and catch criminals$$, $$/dɪˈtektɪv/$$, $$The detective found important clues at the playground.$$, $$侦探$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 1$$, $$queue$$, $$a line of people, cars, etc. waiting for something or to do something$$, $$/kjuː/$$, $$We stood in a long queue to buy ice cream.$$, $$队伍；排队的人$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 1$$, $$mechanic$$, $$a person whose job is repairing machines, especially the engines of vehicles$$, $$/məˈkænɪk/$$, $$The mechanic fixed our car after it broke down on holiday.$$, $$机械师；修理工$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 1$$, $$opinion$$, $$your feelings or thoughts about somebody/something, rather than a fact$$, $$/əˈpɪnjən/$$, $$In my opinion, chocolate ice cream is the best flavour.$$, $$观点；看法$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 1$$, $$reporter$$, $$a person who collects and reports news for newspapers, radio or television$$, $$/rɪˈpɔːtə(r)/$$, $$The reporter asked the children about their school sports day.$$, $$记者$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 1$$, $$skill$$, $$a particular ability or type of ability$$, $$/skɪl/$$, $$Riding a bike is a useful skill to learn.$$, $$技能；技巧$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 1$$, $$sailor$$, $$a person who works on a ship as a member of the crew$$, $$/ˈseɪlə(r)/$$, $$The brave sailor waved to us from the big ship.$$, $$水手；船员$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 1$$, $$tax$$, $$money that you have to pay to the government so that it can pay for public services$$, $$/tæks/$$, $$Dad said we pay tax to help build new schools and roads.$$, $$税；税款$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 1$$, $$desire$$, $$a strong wish to have or do something$$, $$/dɪˈzaɪə(r)/$$, $$She had a strong desire to visit the zoo on Saturday.$$, $$渴望；愿望$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 1$$, $$sense$$, $$one of the five powers (sight, hearing, smell, taste and touch) that your body uses to get information about the world around you$$, $$/sens/$$, $$Dogs have a much better sense of smell than people.$$, $$感官；知觉$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 1$$, $$taste$$, $$the sense you have that allows you to recognize different foods and drinks when you put them in your mouth$$, $$/teɪst/$$, $$My sense of taste is weaker when I have a cold.$$, $$味觉$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 1$$, $$taste (verb)$$, $$to test the taste of something by eating or drinking a small amount of it$$, $$/teɪst/$$, $$Please taste the soup and tell me if it needs more salt.$$, $$品尝；尝味道$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 2$$, $$designer$$, $$a person who plans how something new will look and be made$$, $$/dɪˈzaɪnə(r)/$$, $$The designer drew a pretty dress for the school play.$$, $$设计师$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 2$$, $$day off$$, $$a day on which you do not have to work$$, $$/deɪ ɒf/$$, $$Mum took a day off so we could go to the park.$$, $$休息日$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 2$$, $$focus on$$, $$to give attention, effort, or energy to one specific task, goal, or activity$$, $$/ˈfəʊkəs ɒn/$$, $$Try to focus on your reading and ignore the noise outside.$$, $$专注于；集中于$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 2$$, $$full-time$$, $$done during the full number of hours considered normal or standard$$, $$/ˌfʊl ˈtaɪm/$$, $$My dad has a full-time job at the hospital.$$, $$全职的$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 2$$, $$part-time$$, $$working or involving fewer hours than is considered normal or standard$$, $$/ˌpɑːt ˈtaɪm/$$, $$My aunt has a part-time job at the small bakery.$$, $$兼职的$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 2$$, $$job$$, $$the work that a person does regularly in order to earn money$$, $$/dʒɒb/$$, $$My mum has a job at a busy children's hospital.$$, $$工作；职业$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 2$$, $$author$$, $$a person who writes books or the person who wrote a particular book$$, $$/ˈɔːθə(r)/$$, $$The author of my favourite story book visited our school.$$, $$作家；作者$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 2$$, $$career$$, $$the job or series of jobs that you do during your working life, especially if you continue to get better jobs and earn more money$$, $$/kəˈrɪə(r)/$$, $$She wants a career as a doctor when she grows up.$$, $$职业；事业$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 2$$, $$employee$$, $$a person who is paid to work for somebody$$, $$/ɪmˈplɔɪiː/$$, $$Every employee at the toy shop wore a bright red shirt.$$, $$雇员；员工$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 2$$, $$experience$$, $$the knowledge and skill that you have gained through doing something for a period of time$$, $$/ɪkˈspɪəriəns/$$, $$Grandma has lots of experience baking yummy birthday cakes.$$, $$经验；经历$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 2$$, $$manager$$, $$a person who is in charge of running a business, a shop or a similar organisation or part of one$$, $$/ˈmænɪdʒə(r)/$$, $$The manager of the bookshop helped us find a fun story.$$, $$经理；管理者$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 2$$, $$staff$$, $$a group of people who work for an organisation or business$$, $$/stɑːf/$$, $$The staff at our school are kind and very helpful.$$, $$全体员工$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 2$$, $$organisation (AmE organization)$$, $$a group of people who form a business, club, etc. together in order to achieve a particular aim$$, $$/ˌɔːɡənaɪˈzeɪʃn/$$, $$We joined an organisation that helps look after stray puppies.$$, $$组织；机构$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 2$$, $$the Arctic$$, $$the regions of the world around the North Pole$$, $$/ðə ˈɑːktɪk/$$, $$Polar bears and seals live in the Arctic all year round.$$, $$北极地区$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 2$$, $$surface$$, $$the outside or top layer of something$$, $$/ˈsɜːfɪs/$$, $$Tiny ants crawled across the surface of the picnic table.$$, $$表面$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 2$$, $$rover$$, $$a spacecraft designed to move on a planet or moon$$, $$/ˈrəʊvə(r)/$$, $$The rover sent back amazing photos from the surface of Mars.$$, $$漫游车；探测车$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 2$$, $$greenhouse$$, $$a building with glass sides and a glass roof for growing plants in$$, $$/ˈɡriːnhaʊs/$$, $$Grandpa grows juicy tomatoes inside his little greenhouse.$$, $$温室；暖房$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 2$$, $$shelter$$, $$a structure built to give protection, especially from the weather or from attack$$, $$/ˈʃeltə(r)/$$, $$We built a shelter from branches to hide from the rain.$$, $$避难所；遮蔽处$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 2$$, $$planetary$$, $$relating to a planet or planets$$, $$/ˈplænətri/$$, $$The museum had a cool planetary display about Jupiter and Mars.$$, $$行星的$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 2$$, $$toxic$$, $$containing poison$$, $$/ˈtɒksɪk/$$, $$Never touch toxic plants or berries you find in the woods.$$, $$有毒的$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 2$$, $$dust$$, $$a fine powder that consists of very small pieces of sand, earth, etc.$$, $$/dʌst/$$, $$There was a thick layer of dust on the old toy box.$$, $$灰尘；尘土$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 3$$, $$submarine$$, $$a ship that can travel underwater$$, $$/ˌsʌbməˈriːn/$$, $$The yellow submarine dived deep to see colourful fish.$$, $$潜水艇$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 3$$, $$attract$$, $$to cause (someone or something) to go to or move to or towards a place$$, $$/əˈtrækt/$$, $$Sweet flowers attract bees and butterflies to our garden.$$, $$吸引$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 3$$, $$brave$$, $$willing to do things that are difficult or dangerous; not afraid$$, $$/breɪv/$$, $$My little brother was very brave at the dentist today.$$, $$勇敢的$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 3$$, $$professional$$, $$doing something as a paid job rather than as a hobby$$, $$/prəˈfeʃənl/$$, $$My cousin is a professional football player on a big team.$$, $$专业的；职业的$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 3$$, $$worry$$, $$something that worries you$$, $$/ˈwʌri/$$, $$My biggest worry is forgetting my lines in the school play.$$, $$烦恼；担忧的事$$),
  ($$4B$$, $$Unit 12$$, $$Lesson 3$$, $$seriously$$, $$in a serious way$$, $$/ˈsɪəriəsli/$$, $$The coach spoke seriously about playing safely on the field.$$, $$严肃地；认真地$$)
) AS d(stage, unit, lesson, word, explanation, ipa, example, chinese_def);

